__kernel void benchmark_func(T seed, __global T* src) {
    size_t global_id = get_global_id(0);
    size_t local_id = get_local_id(0);
    size_t group_id = get_group_id(0);
    size_t num_groups = get_num_groups(0);
    size_t block_size = blockdim;
    size_t elements_per_thread = ELEMENTS_PER_THREAD;
    size_t fusion_degree = FUSION_DEGREE;

    size_t stride = block_size * elements_per_thread * fusion_degree;

#ifdef BLOCK_STRIDED
    size_t base_idx = group_id * stride;
#else
    size_t base_idx = global_id * elements_per_thread;
#endif

    T sum = 0;
    T f = seed;

    for (size_t fusion_idx = 0; fusion_idx < fusion_degree; fusion_idx++) {
        size_t elem_offset = fusion_idx * block_size * elements_per_thread;

#ifdef BLOCK_STRIDED
        size_t thread_base = base_idx + elem_offset + local_id * elements_per_thread;
#else
        size_t thread_base = base_idx + elem_offset;
#endif

        for (size_t elem_idx = 0; elem_idx < elements_per_thread; elem_idx++) {
            size idx = thread_base + elem_idx;
            T t = src[idx];

            for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
                t = t * t + f;
            }

            sum += t;
        }
    }

    src[global_id] = sum;
}

__kernel void benchmark_func_warmup(short seed, __global double* src) {
    size_t global_id = get_global_id(0);
    size_t local_id = get_local_id(0);
    size_t group_id = get_group_id(0);
    size_t block_size = blockdim;

    size_t stride = block_size * 8;
    size_t base_idx = group_id * stride + local_id * 8;

    double sum = 0;
    double f = 1.0;

    for (size_t elem_idx = 0; elem_idx < 8; elem_idx++) {
        size idx = base_idx + elem_idx;
        double t = src[idx];

        for (size_t j = 0; j < 16; j++) {
            t = t * t + f;
        }

        sum += t;
    }

    src[global_id] = sum;
}

